function solve(n: number, edges: number[][], label: string): number {
    const graph: number[][] = Array(n).fill(null).map(() => []);
    for (const [u, v] of edges) {
        graph[u].push(v);
        graph[v].push(u);
    }

    const dp: number[][][] = Array(1 << n);
    for (let mask = 0; mask < (1 << n); mask++) {
        dp[mask] = Array(n);
        for (let i = 0; i < n; i++) {
            dp[mask][i] = Array(n).fill(0);
        }
    }

    for (let i = 0; i < n; i++) {
        const mask = 1 << i;
        dp[mask][i][i] = 1;
    }

    for (const [u, v] of edges) {
        if (label[u] === label[v]) {
            const mask = (1 << u) | (1 << v);
            dp[mask][u][v] = 2;
            dp[mask][v][u] = 2;
        }
    }

    let ans = 1;

    for (let mask = 0; mask < (1 << n); mask++) {
        for (let i = 0; i < n; i++) {
            for (let j = 0; j < n; j++) {
                if (dp[mask][i][j] === 0) continue;
                ans = Math.max(ans, dp[mask][i][j]);

                for (const u of graph[i]) {
                    if (mask & (1 << u)) continue;
                    for (const v of graph[j]) {
                        if (u === v) continue;
                        if (mask & (1 << v)) continue;
                        if (label[u] !== label[v]) continue;
                        const newMask = mask | (1 << u) | (1 << v);
                        const newVal = dp[mask][i][j] + 2;
                        if (newVal > dp[newMask][u][v]) {
                            dp[newMask][u][v] = newVal;
                        }
                    }
                }
            }
        }
    }

    return ans;
}
