function solve(n: number, edges: number[][], label: string): number {
    const maxMask = 1 << n;
    const popcounts = new Array(maxMask).fill(0);
    for (let i = 0; i < maxMask; i++) {
        let cnt = 0;
        let m = i;
        while (m) {
            cnt++;
            m &= m - 1;
        }
        popcounts[i] = cnt;
    }

    const adj: number[][] = Array(n).fill(null).map(() => []);
    for (const [u, v] of edges) {
        adj[u].push(v);
        adj[v].push(u);
    }

    const visited: boolean[][][] = Array(maxMask).fill(null).map(
        () => Array(n).fill(null).map(() => Array(n).fill(false))
    );
    const dp: number[][][] = Array(maxMask).fill(null).map(() => []);
    let ans = 1;

    for (let i = 0; i < n; i++) {
        const mask = 1 << i;
        visited[mask][i][i] = true;
        dp[mask].push([i, i]);
    }

    for (const [u, v] of edges) {
        if (label[u] === label[v]) {
            const mask = (1 << u) | (1 << v);
            if (!visited[mask][u][v]) {
                visited[mask][u][v] = true;
                dp[mask].push([u, v]);
                ans = Math.max(ans, 2);
            }
        }
    }

    for (let mask = 0; mask < maxMask; mask++) {
        for (const [i, j] of dp[mask]) {
            for (const u of adj[i]) {
                if (mask & (1 << u)) continue;
                for (const v of adj[j]) {
                    if (mask & (1 << v)) continue;
                    if (u === v) continue;
                    if (label[u] !== label[v]) continue;
                    const new_mask = mask | (1 << u) | (1 << v);
                    if (!visited[new_mask][u][v]) {
                        visited[new_mask][u][v] = true;
                        dp[new_mask].push([u, v]);
                        const cnt = popcounts[new_mask];
                        if (cnt > ans) {
                            ans = cnt;
                        }
                    }
                }
            }
        }
    }

    return ans;
}
```

